import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
} from '@nestjs/common';
import { Observable } from 'rxjs';
import { tap } from 'rxjs/operators';
import * as client from 'prom-client';

const labels: Record<string, string> = { 'environment': 'development', 'region': 'us-east-1' };

client.collectDefaultMetrics({
  labels: { 'environment': 'development', 'region': 'us-east-1' },
});

export const httpRequestsTotal = new client.Counter({
  name: 'http_requests_total',
  help: 'Total number of HTTP requests',
  labelNames: ['method', 'route', 'status_code', 'environment', 'region'],
});

export const httpRequestDuration = new client.Histogram({
  name: 'http_request_duration_seconds',
  help: 'HTTP request duration in seconds',
  labelNames: ['method', 'route', 'environment', 'region'],
  buckets: [0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10],
});

export const httpErrorsTotal = new client.Counter({
  name: 'http_errors_total',
  help: 'Total number of HTTP errors (4xx and 5xx)',
  labelNames: ['method', 'route', 'status_code', 'environment', 'region'],
});

@Injectable()
export class MetricsInterceptor implements NestInterceptor {
  intercept(context: ExecutionContext, next: CallHandler): Observable<unknown> {
    const request = context.switchToHttp().getRequest();
    const method = request.method;
    const route = request.route?.path ?? request.url;
    const startTime = Date.now();

    return next.handle().pipe(
      tap({
        next: () => {
          const response = context.switchToHttp().getResponse();
          const statusCode = response.statusCode?.toString() ?? '200';
          const duration = (Date.now() - startTime) / 1000;

          httpRequestsTotal.inc({
            method,
            route,
            status_code: statusCode
            ,
            ...labels,
            ...labels
          });
          httpRequestDuration.observe(
            { method, route,
            ...labels,
            ...labels },
            duration,
          );
          if (parseInt(statusCode, 10) >= 400) {
            httpErrorsTotal.inc({
              method,
              route,
              status_code: statusCode
              ,
            ...labels,
            ...labels
            });
          }
        },
        error: () => {
          const duration = (Date.now() - startTime) / 1000;
          httpRequestsTotal.inc({
            method,
            route,
            status_code: '500'
            ,
            ...labels,
            ...labels
          });
          httpRequestDuration.observe(
            { method, route,
            ...labels,
            ...labels },
            duration,
          );
          httpErrorsTotal.inc({
            method,
            route,
            status_code: '500'
            ,
            ...labels,
            ...labels
          });
        },
      }),
    );
  }
}
